from flask import Flask, request, jsonify
from flask_jwt import JWTManager, jwt_required
import jwt
import datetime
from hashlib import sha256
import base64
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = 'super-secret'  # Replace with your own secret key
jwt_manager = JWTManager(app)

def generate_password_hash(password):
    salt = base64.b64encode(os.urandom(32))
    pwhash = sha256(password.encode('utf-8') + salt).hexdigest()
    return pwhash + ':' + salt

def verify_password(stored_password, provided_password):
    salt = stored_password[:64]
    pwhash = stored_password[64:]
    guess = sha256(provided_password.encode('utf-8') + salt).hexdigest()
    return pwhash == guess

@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    if not data or 'password' not in data:
        return jsonify({"message": "Missing password"}), 400

    password = generate_password_hash(data['password'])
    users[data['username']] = password
    return jsonify({"message": "User created"}), 201

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    if not data or 'username' not in data or 'password' not in data:
        return jsonify({"message": "Missing username or password"}), 400

    if data['username'] not in users:
        return jsonify({"message": "Invalid username"}), 401

    if not verify_password(users[data['username']], data['password']):
        return jsonify({"message": "Invalid password"}), 401

    expiration = datetime.datetime.utcnow() + datetime.timedelta(minutes=30)
    encoded_jwt = jwt.encode(
        {'exp': expiration, 'username': data['username']}, app.config['SECRET_KEY'], algorithm='HS256')

    return jsonify({"token": encoded_jwt.decode('utf-8')}), 200

